package com.enterprise.usermanagement.config;

import com.zaxxer.hikari.HikariConfig;
import com.zaxxer.hikari.HikariDataSource;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import javax.sql.DataSource;
import java.util.Properties;

@Configuration
public class DataSourceConfig {

    @Value("${spring.datasource.url}")
    private String dbUrl;

    @Value("${spring.datasource.username}")
    private String dbUsername;

    @Value("${spring.datasource.password}")
    private String dbPassword;

    @Bean
    public DataSource dataSource() {
        HikariConfig config = new HikariConfig();

        // Enforce SSL with full certificate verification
        String secureUrl = dbUrl;
        if (!secureUrl.contains("sslmode=verify-full")) {
            throw new IllegalStateException(
                "Database connection must use sslmode=verify-full for encrypted communication. " +
                "Current URL does not enforce proper SSL verification."
            );
        }
        if (!secureUrl.contains("ssl=true")) {
            throw new IllegalStateException(
                "Database connection must have ssl=true enabled."
            );
        }

        config.setJdbcUrl(secureUrl);
        config.setUsername(dbUsername);
        config.setPassword(dbPassword);
        config.setDriverClassName("org.postgresql.Driver");

        // Additional SSL properties for the PostgreSQL driver
        Properties dsProperties = new Properties();
        dsProperties.setProperty("ssl", "true");
        dsProperties.setProperty("sslmode", "verify-full");
        config.setDataSourceProperties(dsProperties);

        config.setMaximumPoolSize(10);
        config.setMinimumIdle(2);
        config.setIdleTimeout(30000);
        config.setConnectionTimeout(20000);
        config.setMaxLifetime(1800000);

        // Validate connection on checkout
        config.setConnectionTestQuery("SELECT 1");

        return new HikariDataSource(config);
    }
}


