package com.enterprise.usermanagement.repository;

import com.enterprise.usermanagement.entity.Transaction;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Repository;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;
import java.util.Optional;

@Repository
public interface TransactionRepository extends JpaRepository<Transaction, Long> {

    Optional<Transaction> findByReferenceNumber(String referenceNumber);

    Page<Transaction> findByUserId(Long userId, Pageable pageable);

    List<Transaction> findByUserIdAndStatus(Long userId, String status);

    @Query("SELECT t FROM Transaction t WHERE t.user.id = :userId " +
           "AND t.createdAt BETWEEN :startDate AND :endDate ORDER BY t.createdAt DESC")
    List<Transaction> findByUserIdAndDateRange(
            @Param("userId") Long userId,
            @Param("startDate") LocalDateTime startDate,
            @Param("endDate") LocalDateTime endDate);

    @Query("SELECT SUM(t.amount) FROM Transaction t WHERE t.user.id = :userId " +
           "AND t.transactionType = :type AND t.status = 'COMPLETED'")
    BigDecimal sumAmountByUserAndType(
            @Param("userId") Long userId,
            @Param("type") String type);

    @Query("SELECT t FROM Transaction t WHERE t.status = 'PENDING' " +
           "AND t.createdAt < :cutoffTime ORDER BY t.createdAt ASC")
    List<Transaction> findStalePendingTransactions(@Param("cutoffTime") LocalDateTime cutoffTime);
}


