package com.enterprise.usermanagement.service;

import com.enterprise.usermanagement.dto.TransactionDTO;
import com.enterprise.usermanagement.entity.Transaction;
import com.enterprise.usermanagement.entity.User;
import com.enterprise.usermanagement.exception.ResourceNotFoundException;
import com.enterprise.usermanagement.exception.TransactionProcessingException;
import com.enterprise.usermanagement.repository.TransactionRepository;
import com.enterprise.usermanagement.repository.UserRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Isolation;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;
import java.util.UUID;
import java.util.stream.Collectors;

@Service
@Transactional
public class TransactionService {

    private static final Logger logger = LoggerFactory.getLogger(TransactionService.class);

    private final TransactionRepository transactionRepository;
    private final UserRepository userRepository;

    public TransactionService(TransactionRepository transactionRepository, UserRepository userRepository) {
        this.transactionRepository = transactionRepository;
        this.userRepository = userRepository;
    }

    @Transactional(isolation = Isolation.SERIALIZABLE)
    public TransactionDTO createTransaction(TransactionDTO transactionDTO) {
        User user = userRepository.findById(transactionDTO.getUserId())
                .orElseThrow(() -> new ResourceNotFoundException("User not found with ID: " + transactionDTO.getUserId()));

        if (!user.isActive()) {
            throw new TransactionProcessingException("Cannot create transaction for inactive user");
        }

        Transaction transaction = new Transaction();
        transaction.setUser(user);
        transaction.setTransactionType(transactionDTO.getTransactionType());
        transaction.setAmount(transactionDTO.getAmount());
        transaction.setCurrency(transactionDTO.getCurrency() != null ? transactionDTO.getCurrency() : "USD");
        transaction.setStatus("PENDING");
        transaction.setDescription(transactionDTO.getDescription());
        transaction.setReferenceNumber(generateReferenceNumber());

        Transaction savedTransaction = transactionRepository.save(transaction);
        logger.info("Transaction created with reference: {}", savedTransaction.getReferenceNumber());
        return mapToDTO(savedTransaction);
    }

    @Transactional(isolation = Isolation.SERIALIZABLE)
    public TransactionDTO processTransaction(Long transactionId) {
        Transaction transaction = transactionRepository.findById(transactionId)
                .orElseThrow(() -> new ResourceNotFoundException("Transaction not found with ID: " + transactionId));

        if (!"PENDING".equals(transaction.getStatus())) {
            throw new TransactionProcessingException(
                    "Transaction cannot be processed. Current status: " + transaction.getStatus());
        }

        try {
            transaction.setStatus("COMPLETED");
            transaction.setProcessedAt(LocalDateTime.now());
            Transaction processedTransaction = transactionRepository.save(transaction);
            logger.info("Transaction processed successfully: {}", processedTransaction.getReferenceNumber());
            return mapToDTO(processedTransaction);
        } catch (Exception e) {
            transaction.setStatus("FAILED");
            transactionRepository.save(transaction);
            logger.error("Transaction processing failed: {}", transaction.getReferenceNumber(), e);
            throw new TransactionProcessingException("Transaction processing failed: " + e.getMessage());
        }
    }

    @Transactional(readOnly = true)
    public TransactionDTO getTransactionByReference(String referenceNumber) {
        Transaction transaction = transactionRepository.findByReferenceNumber(referenceNumber)
                .orElseThrow(() -> new ResourceNotFoundException("Transaction not found with reference: " + referenceNumber));
        return mapToDTO(transaction);
    }

    @Transactional(readOnly = true)
    public Page<TransactionDTO> getUserTransactions(Long userId, Pageable pageable) {
        return transactionRepository.findByUserId(userId, pageable).map(this::mapToDTO);
    }

    @Transactional(readOnly = true)
    public List<TransactionDTO> getUserTransactionsByDateRange(Long userId, LocalDateTime startDate, LocalDateTime endDate) {
        return transactionRepository.findByUserIdAndDateRange(userId, startDate, endDate).stream()
                .map(this::mapToDTO)
                .collect(Collectors.toList());
    }

    @Transactional(readOnly = true)
    public BigDecimal getUserTransactionSum(Long userId, String transactionType) {
        BigDecimal sum = transactionRepository.sumAmountByUserAndType(userId, transactionType);
        return sum != null ? sum : BigDecimal.ZERO;
    }

    public void cancelTransaction(Long transactionId) {
        Transaction transaction = transactionRepository.findById(transactionId)
                .orElseThrow(() -> new ResourceNotFoundException("Transaction not found with ID: " + transactionId));

        if ("COMPLETED".equals(transaction.getStatus())) {
            throw new TransactionProcessingException("Cannot cancel a completed transaction");
        }

        transaction.setStatus("CANCELLED");
        transactionRepository.save(transaction);
        logger.info("Transaction cancelled: {}", transaction.getReferenceNumber());
    }

    private String generateReferenceNumber() {
        return "TXN-" + UUID.randomUUID().toString().replace("-", "").substring(0, 16).toUpperCase();
    }

    private TransactionDTO mapToDTO(Transaction transaction) {
        TransactionDTO dto = new TransactionDTO();
        dto.setId(transaction.getId());
        dto.setUserId(transaction.getUser().getId());
        dto.setTransactionType(transaction.getTransactionType());
        dto.setAmount(transaction.getAmount());
        dto.setCurrency(transaction.getCurrency());
        dto.setStatus(transaction.getStatus());
        dto.setDescription(transaction.getDescription());
        dto.setReferenceNumber(transaction.getReferenceNumber());
        dto.setCreatedAt(transaction.getCreatedAt());
        dto.setProcessedAt(transaction.getProcessedAt());
        return dto;
    }
}


